// SPDX-License-Identifier: GPL-2.0-only
/*
 * Virtual GPIO multiplexer driver
 *
 * This driver provides a 1-to-many mapping between virtual GPIOs and a
 * single real GPIO using a mux controller. Each virtual GPIO corresponds
 * to a mux channel. When accessed, the driver selects the appropriate
 * mux channel, operates on the underlying GPIO, then deselects the mux.
 *
 * Copyright (C) 2024
 */

#include <linux/bitmap.h>
#include <linux/device.h>
#include <linux/err.h>
#include <linux/gpio/consumer.h>
#include <linux/gpio/driver.h>
#include <linux/module.h>
#include <linux/mod_devicetable.h>
#include <linux/mux/consumer.h>
#include <linux/platform_device.h>
#include <linux/property.h>

struct gpio_virtmux {
	struct gpio_chip gc;
	struct mux_control *mux;
	struct gpio_desc *desc;
	unsigned long *dirs;
};

static int gpio_virtmux_get(struct gpio_chip *gc, unsigned int offset)
{
	struct gpio_virtmux *virtmux = gpiochip_get_data(gc);
	int ret, val;

	ret = mux_control_select(virtmux->mux, offset);
	if (ret)
		return ret;

	val = gpiod_get_value_cansleep(virtmux->desc);

	mux_control_deselect(virtmux->mux);

	return val;
}

static void gpio_virtmux_set(struct gpio_chip *gc, unsigned int offset, int val)
{
	struct gpio_virtmux *virtmux = gpiochip_get_data(gc);
	int ret;

	ret = mux_control_select(virtmux->mux, offset);
	if (ret)
		return;

	gpiod_set_value_cansleep(virtmux->desc, val);

	mux_control_deselect(virtmux->mux);
}

static int gpio_virtmux_direction_input(struct gpio_chip *gc,
					unsigned int offset)
{
	struct gpio_virtmux *virtmux = gpiochip_get_data(gc);
	int ret;

	ret = mux_control_select(virtmux->mux, offset);
	if (ret)
		return ret;

	ret = gpiod_direction_input(virtmux->desc);
	if (ret) {
		mux_control_deselect(virtmux->mux);
		return ret;
	}

	__clear_bit(offset, virtmux->dirs);

	mux_control_deselect(virtmux->mux);

	return 0;
}

static int gpio_virtmux_direction_output(struct gpio_chip *gc,
					 unsigned int offset, int val)
{
	struct gpio_virtmux *virtmux = gpiochip_get_data(gc);
	int ret;

	ret = mux_control_select(virtmux->mux, offset);
	if (ret)
		return ret;

	ret = gpiod_direction_output(virtmux->desc, val);
	if (ret) {
		mux_control_deselect(virtmux->mux);
		return ret;
	}

	__set_bit(offset, virtmux->dirs);

	mux_control_deselect(virtmux->mux);

	return 0;
}

static int gpio_virtmux_get_direction(struct gpio_chip *gc,
				      unsigned int offset)
{
	struct gpio_virtmux *virtmux = gpiochip_get_data(gc);

	if (test_bit(offset, virtmux->dirs))
		return GPIO_LINE_DIRECTION_OUT;

	return GPIO_LINE_DIRECTION_IN;
}

static int gpio_virtmux_probe(struct platform_device *pdev)
{
	struct device *dev = &pdev->dev;
	struct gpio_virtmux *virtmux;
	unsigned int ngpios;

	virtmux = devm_kzalloc(dev, sizeof(*virtmux), GFP_KERNEL);
	if (!virtmux)
		return -ENOMEM;

	virtmux->desc = devm_gpiod_get(dev, NULL, GPIOD_ASIS);
	if (IS_ERR(virtmux->desc))
		return dev_err_probe(dev, PTR_ERR(virtmux->desc),
				     "failed to get GPIO\n");

	virtmux->mux = devm_mux_control_get(dev, NULL);
	if (IS_ERR(virtmux->mux))
		return dev_err_probe(dev, PTR_ERR(virtmux->mux),
				     "failed to get mux control\n");

	ngpios = mux_control_states(virtmux->mux);

	virtmux->dirs = devm_bitmap_zalloc(dev, ngpios, GFP_KERNEL);
	if (!virtmux->dirs)
		return -ENOMEM;

	virtmux->gc.label = dev_name(dev);
	virtmux->gc.parent = dev;
	virtmux->gc.owner = THIS_MODULE;
	virtmux->gc.base = -1;
	virtmux->gc.ngpio = ngpios;
	virtmux->gc.can_sleep = true;
	virtmux->gc.get = gpio_virtmux_get;
	virtmux->gc.set = gpio_virtmux_set;
	virtmux->gc.direction_input = gpio_virtmux_direction_input;
	virtmux->gc.direction_output = gpio_virtmux_direction_output;
	virtmux->gc.get_direction = gpio_virtmux_get_direction;

	platform_set_drvdata(pdev, virtmux);

	return devm_gpiochip_add_data(dev, &virtmux->gc, virtmux);
}

static const struct of_device_id gpio_virtmux_of_match[] = {
	{ .compatible = "gpio-virtmux", },
	{ /* sentinel */ }
};
MODULE_DEVICE_TABLE(of, gpio_virtmux_of_match);

static struct platform_driver gpio_virtmux_driver = {
	.driver = {
		.name = "gpio-virtmux",
		.of_match_table = gpio_virtmux_of_match,
	},
	.probe = gpio_virtmux_probe,
};
module_platform_driver(gpio_virtmux_driver);

MODULE_AUTHOR("Kernel Community");
MODULE_DESCRIPTION("Virtual GPIO multiplexer driver");
MODULE_LICENSE("GPL v2");

